C++<pre><code>class A {
    friend class B;  // B 是 A 的友元类
private:
    int data = 100;
};

class B {
public:
    void accessA(A&amp; a) {
        std::cout &lt;&lt; a.data &lt;&lt; std::endl;  // ✅ 可访问 A 的私有成员
    }
};
</code></pre> C++<pre><code>class Building;
