C++<pre><code>class MyInteger {

    friend ostream&amp; operator&lt;&lt;(ostream&amp; out, MyInteger myint);

public:
    MyInteger() {
        m_Num = 0;
    }
    //前置++
    MyInteger&amp; operator++() {
        //先++
        m_Num++;
        //再返回
        return *this;
    }

    //后置++
    MyInteger operator++(int) {
        //先返回
        MyInteger temp = *this; //记录当前本身的值，然后让本身的值加1，但是返回的是以前的值，达到先返回后++；
        m_Num++;
        return temp;
    }

private:
    int m_Num;
};


ostream&amp; operator&lt;&lt;(ostream&amp; out, MyInteger myint) {
    out &lt;&lt; myint.m_Num;
    return out;
}


//前置++ 先++ 再返回
void test01() {
    MyInteger myInt;
    cout &lt;&lt; ++myInt &lt;&lt; endl; // 1
    cout &lt;&lt; myInt &lt;&lt; endl; // 1
}

//后置++ 先返回 再++
void test02() {

    MyInteger myInt;
    cout &lt;&lt; myInt++ &lt;&lt; endl; // 0
    cout &lt;&lt; myInt &lt;&lt; endl; // 1
}

int main() {

    test01();
    test02();

    system("pause");

    return 0;
}
</code></pre> <p>总结： 前置递增返回引用，后置递增返回值</p>

C<pre><code>#include &lt;stdio.h&gt;
#include &lt;stdlib.h&gt;

unsigned char* read_binary_file(const char* filename, size_t* file_size)
{
    FILE* fp = fopen(filename, "rb");
    if (fp == NULL)
    {
        printf("Failed to open file: %s\n", filename);
        return NULL;
    }

    fseek(fp, 0, SEEK_END); // 移动到文件末尾
    *file_size = ftell(fp); // 获取文件大小
    rewind(fp); // 回到文件开头

    unsigned char* buffer = (unsinged char* )malloc(*file_size);

    if(!buffer)
    {
        printf("Memory allocation failed\n");
        fclose(fp);
        return NULL;
    }

    if (fread(buffer, 1, *file_size, fp) != *file_size)
    {
        printf("failed to read file\n");
        free(buffer);
        fclose(fp);
        return NULL;
    }
    fclose(fp);
    return buffer; //返回文件内容
}
</code></pre> <p><code>size_t fread(void *ptr, size_t size, size_t count, FILE *stream);</code> 参数说明 - <code>ptr</code>：指向要存储读取数据的缓冲区（通常是 <code>char*</code> 或 <code>unsigned char*</code>）。 - <code>size</code>：每个数据项的大小（以字节为单位）。 - <code>count</code>：要读取的数据项个数。 - <code>stream</code>：指向 <code>FILE*</code> 文件流。 返回值 返回成功读取的数据项个数（count）。 如果 读取数量小于 count，可能是 文件结束 或 读取出错。</p>

C<pre><code>#include &lt;stdio.h&gt;
#include &lt;stdlib.h&gt;

void read_text_file(const char* filename)
{
    FILE* fp = fopen(filename, "r");
    if (fp ==NULL)
    {
        printf("Failed to open file:%s\n", filename);
        return;
    }
    char buffer[256]; // 缓冲区
    while(fgets(buffer, sizeof(buffer), fp))
    {
        printf("%s", buffer);
    }
    fclose(fp);
}
</code></pre>

C<pre><code>#include &lt;stdio.h&gt;

void read_file_char_by_char(const char* filename)
{
    FILE* fp = fopen(filename, "r");
    if (fp == NULL)
    {
        printf("Failed to open file: %s\n", filename);
        return;
    }
    int ch;
    while((ch = fgetc(fp)) != EOF){
        putchar(ch);
    }
}
