C++<pre><code>#include "Gun.h"
#include "iostream"
using namespace std;

void Gun::addBullet(int bullet_num)
{
    this-&gt;_bullet_count += bullet_num;
}

bool Gun::shoot()
{
    if (this-&gt;_bullet_count &lt;= 0)
    {
        cout &lt;&lt; "There is no bullet!" &lt;&lt; endl;
        return false;
    }

    this-&gt;_bullet_count -= 1;
    cout &lt;&lt; "shoot success" &lt;&lt; endl;
    return true;
}
